const l=`{% block sw_bulk_edit_save_modal_confirm %} <div class="sw-bulk-edit-save-modal-confirm"> <p class="sw-bulk-edit-save-modal__help-text"> {{ $t('sw-bulk-edit.modal.confirm.description', { itemCount: itemTotal }, itemTotal) }} </p> {% block sw_bulk_edit_save_modal_confirm_trigger_flows %} <div v-if="triggeredFlows.length > 0" class="sw-bulk-edit-save-modal-confirm__trigger-flows" > {% block sw_bulk_edit_save_modal_confirm_trigger_flows_switch %} <mt-switch v-if="!bulkEditData?.statusMails?.isChanged" v-model="isFlowTriggered" name="sw-bulk-edit-save-modal-confirm-trigger-flows-switch" class="sw-bulk-edit-save-modal-confirm__trigger-flows-switch" :label="$t('sw-bulk-edit.modal.confirm.switchLabel')" :help-text="$t('sw-bulk-edit.modal.confirm.switchHelpText')" /> {% endblock %} {% block sw_bulk_edit_save_modal_confirm_trigger_flows_alert %} <mt-banner v-show="isFlowTriggered" class="sw-bulk-edit-save-modal-confirm__trigger-flows-alert" > <p>{{ $t('sw-bulk-edit.modal.confirm.alertTitle') }}</p> <span>{{ triggeredFlows.join(', ') }}</span> </mt-banner> {% endblock %} </div> {% endblock %} <mt-banner v-if="hasDocumentDeletionSelected" variant="attention" class="sw-bulk-edit-save-modal__warning-document-deletion" > {{ $t('sw-bulk-edit.modal.warningTextDocumentDeletion') }} </mt-banner> <mt-banner variant="attention" class="sw-bulk-edit-save-modal__warning" > {{ $t('sw-bulk-edit.modal.warningText') }} </mt-banner> </div> {% endblock %}`,s={template:l,emits:["title-set","buttons-update"],props:{itemTotal:{required:!0,type:Number},bulkEditData:{type:Object,required:!1,default:()=>({})}},computed:{isFlowTriggered:{get(){return Shopware.Store.get("swBulkEdit").isFlowTriggered},set(t){Shopware.Store.get("swBulkEdit").setIsFlowTriggered(t)}},triggeredFlows(){const t=[];return Object.entries(this.bulkEditData).forEach(([e,i])=>{e===this.$t(`sw-bulk-edit.modal.confirm.triggeredFlows.${e}.key`)&&i.isChanged===!0&&t.push(this.$t(`sw-bulk-edit.modal.confirm.triggeredFlows.${e}.label`))}),t},hasDocumentDeletionSelected(){var t,e;return((e=(t=this.bulkEditData)==null?void 0:t.delete)==null?void 0:e.isChanged)===!0}},created(){this.createdComponent()},methods:{createdComponent(){this.updateButtons(),this.setTitle()},setTitle(){this.$emit("title-set",this.$t("sw-bulk-edit.modal.confirm.title"))},updateButtons(){const t=[{key:"cancel",label:this.$t("global.sw-modal.labelClose"),position:"left",action:"",disabled:!1},{key:"next",label:this.$t("sw-bulk-edit.modal.confirm.buttons.applyChanges"),position:"right",variant:"primary",action:"process",disabled:!1}];this.$emit("buttons-update",t)}}};export{s as default};
